export class PerformanceTracerManager {
    constructor() {
        this.tracers = [];
    }
    clear() {
        for (let t of this.tracers)
            t.clear();
    }
    start(name) {
        for (let t of this.tracers)
            t.start(name);
    }
    end() {
        for (let t of this.tracers)
            t.end();
    }
}
